import { useState } from "react";
import { Table, TableBody, TableCell, TableContainer, TableHead, TableRow, TableSortLabel, Paper, Checkbox, Toolbar, Typography } from "@sistent/sistent";

export const BasicTableDemo = () => {
  const rows = [
    { name: "meshery", env: "production", status: "Running" },
    { name: "nighthawk", env: "staging", status: "Stopped" },
    { name: "kanvas", env: "development", status: "Running" },
  ];
  return (
    <TableContainer component={Paper}>
      <Table aria-label="basic table">
        <TableHead>
          <TableRow>
            <TableCell>Name</TableCell>
            <TableCell>Environment</TableCell>
            <TableCell>Status</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {rows.map((row) => (
            <TableRow key={row.name}>
              <TableCell>{row.name}</TableCell>
              <TableCell>{row.env}</TableCell>
              <TableCell>{row.status}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
};

export const SortableTableDemo = () => {
  const [order, setOrder] = useState("asc");
  const [orderBy, setOrderBy] = useState("name");
  const initialRows = [
    { name: "meshery", version: "v0.7.1" },
    { name: "kanvas", version: "v0.5.0" },
    { name: "nighthawk", version: "v0.9.3" },
  ];
  const handleSort = (column) => {
    const isAsc = orderBy === column && order === "asc";
    setOrder(isAsc ? "desc" : "asc");
    setOrderBy(column);
  };
  const sorted = [...initialRows].sort((a, b) => {
    if (a[orderBy] < b[orderBy]) return order === "asc" ? -1 : 1;
    if (a[orderBy] > b[orderBy]) return order === "asc" ? 1 : -1;
    return 0;
  });
  return (
    <TableContainer component={Paper}>
      <Table aria-label="sortable table">
        <TableHead>
          <TableRow>
            {["name", "version"].map((col) => (
              <TableCell key={col} sortDirection={orderBy === col ? order : false}>
                <TableSortLabel
                  active={orderBy === col}
                  direction={orderBy === col ? order : "asc"}
                  onClick={() => handleSort(col)}
                >
                  {col.charAt(0).toUpperCase() + col.slice(1)}
                </TableSortLabel>
              </TableCell>
            ))}
          </TableRow>
        </TableHead>
        <TableBody>
          {sorted.map((row) => (
            <TableRow key={row.name}>
              <TableCell>{row.name}</TableCell>
              <TableCell>{row.version}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
};

export const SelectableTableDemo = () => {
  const rows = [
    { id: 1, name: "meshery", env: "production" },
    { id: 2, name: "kanvas", env: "staging" },
    { id: 3, name: "nighthawk", env: "development" },
  ];
  const [selected, setSelected] = useState([]);
  const isSelected = (id) => selected.includes(id);
  const handleSelectAll = (e) => {
    setSelected(e.target.checked ? rows.map((r) => r.id) : []);
  };
  const handleSelect = (id) => {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id]
    );
  };
  return (
    <Paper>
      <Toolbar>
        <Typography variant="subtitle1">
          {selected.length > 0 ? selected.length + " selected" : "Services"}
        </Typography>
      </Toolbar>
      <TableContainer>
        <Table aria-label="selectable table">
          <TableHead>
            <TableRow>
              <TableCell padding="checkbox">
                <Checkbox
                  indeterminate={selected.length > 0 && selected.length < rows.length}
                  checked={rows.length > 0 && selected.length === rows.length}
                  onChange={handleSelectAll}
                  inputProps={{ "aria-label": "select all" }}
                />
              </TableCell>
              <TableCell>Name</TableCell>
              <TableCell>Environment</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rows.map((row) => (
              <TableRow
                key={row.id}
                selected={isSelected(row.id)}
                onClick={() => handleSelect(row.id)}
                hover
                style={{ cursor: "pointer" }}
              >
                <TableCell padding="checkbox">
                  <Checkbox
                    checked={isSelected(row.id)}
                    inputProps={{ "aria-label": "select " + row.name }}
                  />
                </TableCell>
                <TableCell>{row.name}</TableCell>
                <TableCell>{row.env}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Paper>
  );
};

export const PaginatedTableDemo = () => {
  const allRows = Array.from({ length: 5 }, (_, i) => ({
    id: i + 1,
    name: "service-" + (i + 1),
    status: i % 2 === 0 ? "Running" : "Stopped",
  }));
  return (
    <TableContainer component={Paper}>
      <Table aria-label="paginated table">
        <TableHead>
          <TableRow>
            <TableCell>#</TableCell>
            <TableCell>Name</TableCell>
            <TableCell>Status</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {allRows.map((row) => (
            <TableRow key={row.id}>
              <TableCell>{row.id}</TableCell>
              <TableCell>{row.name}</TableCell>
              <TableCell>{row.status}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
};

