<a id="Sortable Table">
  <h2>Sortable Table</h2>
</a>

Column headers wrapped in <code>TableSortLabel</code> allow ascending/descending ordering.

<div className="showcase">
  <div className="items">
    <ThemeWrapper>
      <SortableTableDemo />
    </ThemeWrapper>
  </div>
  <CodeBlock name="sortable-table" collapsible code={`import { useState } from "react";
import {
  Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, TableSortLabel, Paper,
} from "@sistent/sistent";

const initialRows = [
  { name: "meshery", version: "v0.7.1" },
  { name: "kanvas", version: "v0.5.0" },
  { name: "nighthawk", version: "v0.9.3" },
];

export default function SortableTable() {
  const [order, setOrder] = useState("asc");
  const [orderBy, setOrderBy] = useState("name");

  const handleSort = (column) => {
    const isAsc = orderBy === column && order === "asc";
    setOrder(isAsc ? "desc" : "asc");
    setOrderBy(column);
  };

  const sorted = [...initialRows].sort((a, b) => {
    if (a[orderBy] < b[orderBy]) return order === "asc" ? -1 : 1;
    if (a[orderBy] > b[orderBy]) return order === "asc" ? 1 : -1;
    return 0;
  });

  return (
    <TableContainer component={Paper}>
      <Table aria-label="sortable table">
        <TableHead>
          <TableRow>
            {["name", "version"].map((col) => (
              <TableCell key={col} sortDirection={orderBy === col ? order : false}>
                <TableSortLabel
                  active={orderBy === col}
                  direction={orderBy === col ? order : "asc"}
                  onClick={() => handleSort(col)}
                >
                  {col.charAt(0).toUpperCase() + col.slice(1)}
