}`} />
</div>

<a id="Selectable Rows Table">
  <h2>Selectable Rows Table</h2>
</a>

Rows include a leading <code>Checkbox</code> for single or bulk selection.

<div className="showcase">
  <div className="items">
    <ThemeWrapper>
      <SelectableTableDemo />
    </ThemeWrapper>
  </div>
  <CodeBlock name="selectable-table" collapsible code={`import { useState } from "react";
import {
  Table, TableBody, TableCell, TableContainer, TableHead,
  TableRow, Paper, Checkbox, Toolbar, Typography,
} from "@sistent/sistent";

const rows = [
  { id: 1, name: "meshery", env: "production" },
  { id: 2, name: "kanvas", env: "staging" },
  { id: 3, name: "nighthawk", env: "development" },
];

export default function SelectableTable() {
  const [selected, setSelected] = useState([]);

  const isSelected = (id) => selected.includes(id);

  const handleSelectAll = (e) => {
    setSelected(e.target.checked ? rows.map((r) => r.id) : []);
  };

  const handleSelect = (id) => {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id]
    );
  };

  return (
    <Paper>
      <Toolbar>
        <Typography variant="subtitle1">
          {selected.length > 0 ? selected.length + " selected" : "Services"}
        </Typography>
      </Toolbar>
      <TableContainer>
        <Table aria-label="selectable table">
          <TableHead>
            <TableRow>
              <TableCell padding="checkbox">
                <Checkbox
                  indeterminate={selected.length > 0 && selected.length < rows.length}
                  checked={rows.length > 0 && selected.length === rows.length}
                  onChange={handleSelectAll}
                  inputProps={{ "aria-label": "select all" }}
                />
              </TableCell>
              <TableCell>Name</TableCell>
              <TableCell>Environment</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {rows.map((row) => (
              <TableRow
                key={row.id}
                selected={isSelected(row.id)}
                onClick={() => handleSelect(row.id)}
                hover
                style={{ cursor: "pointer" }}
              >
                <TableCell padding="checkbox">
                  <Checkbox
                    checked={isSelected(row.id)}
                    inputProps={{ "aria-label": "select " + row.name }}
                  />
                </TableCell>
                <TableCell>{row.name}</TableCell>
                <TableCell>{row.env}</TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Paper>
  );
}`} />
</div>

<a id="Paginated Table">
  <h2>Paginated Table</h2>
</a>

<code>TablePagination</code> in the footer controls which page of rows is displayed.

<div className="showcase">
  <div className="items">
    <ThemeWrapper>
      <PaginatedTableDemo />
    </ThemeWrapper>
  </div>
  <CodeBlock name="paginated-table" collapsible code={`import { useState } from "react";
import {
  Table, TableBody, TableCell, TableContainer, TableFooter,
  TableHead, TablePagination, TableRow, Paper,
} from "@sistent/sistent";

const allRows = Array.from({ length: 30 }, (_, i) => ({
  id: i + 1,
  name: "service-" + (i + 1),
  status: i % 2 === 0 ? "Running" : "Stopped",
}));

export default function PaginatedTable() {
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);

  const handleChangePage = (_, newPage) => setPage(newPage);
  const handleChangeRowsPerPage = (e) => {
    setRowsPerPage(parseInt(e.target.value, 10));
    setPage(0);
  };

  const visibleRows = allRows.slice(
    page * rowsPerPage,
    page * rowsPerPage + rowsPerPage
  );

  return (
    <TableContainer component={Paper}>
      <Table aria-label="paginated table">
        <TableHead>
          <TableRow>
            <TableCell>#</TableCell>
            <TableCell>Name</TableCell>
            <TableCell>Status</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {visibleRows.map((row) => (
            <TableRow key={row.id}>
              <TableCell>{row.id}</TableCell>
              <TableCell>{row.name}</TableCell>
              <TableCell>{row.status}</TableCell>
            </TableRow>
          ))}
        </TableBody>
        <TableFooter>
          <TableRow>
            <TablePagination
              rowsPerPageOptions={[10, 25, 50]}
              count={allRows.length}
              rowsPerPage={rowsPerPage}
              page={page}
              onPageChange={handleChangePage}
              onRowsPerPageChange={handleChangeRowsPerPage}
            />
          </TableRow>
        </TableFooter>
      </Table>
    </TableContainer>
  );
}`} />
</div>
